package files

import (
	shipqsrc "github.com/shipq/shipq"
)

// GenerateTypeScriptHelpers returns the shipq-files.ts content for writing
// into user projects. The source of truth is admin/src/shipq-files.ts,
// embedded at build time via go:embed in embed_sources.go.
func GenerateTypeScriptHelpers() []byte {
	// Prepend the "do not edit" header for generated copies.
	header := []byte("// Generated by shipq. Do not edit.\n// Source: https://github.com/shipq/shipq\n")
	return append(header, shipqsrc.ShipqFilesTS...)
}
